#[strum(serialize_all = "snake_case")]
pub enum BackendType {
    Aqua,
    Asdf,
    Cargo,
    Conda,
    Core,
    Dotnet,
    Forgejo,
    Gem,
    Github,
    Gitlab,
    Go,
